def rgb_to_hsv(r, g, b):
    r /= 255.0
    g /= 255.0
    b /= 255.0

    mx = max(r, g, b)
    mn = min(r, g, b)
    df = mx - mn

    if mx == mn:
        h = 0
    elif mx == r:
        h = (60 * ((g - b) / df)) % 360
    elif mx == g:
        h = (60 * ((b - r) / df)) + 120
    else:
        h = (60 * ((r - g) / df)) + 240

    s = 0 if mx == 0 else (df / mx) * 100
    v = mx * 100

    return round(h), round(s, 1), round(v, 1)

def mul_even_odd(arr):
    evn = -1
    odd = -1
    for i in range(len(arr)):
        if arr[i] % 2 == 0:
            if evn == -1:
                evn = arr[i]
        else:
            if odd == -1:
                odd = arr[i]
        if evn != -1 and odd != -1:
            break
    return evn * odd

def right_insertion(nums, x):
    l, r = 0, len(nums)
    while l < r:
        m = (l + r) // 2
        if nums[m] <= x:
            l = m + 1
        else:
            r = m
    return l

